INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('police-8b7f1efc-moex-00067', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '關於警察機關處理家暴案件之程序重點，下列何者錯誤？', '["在完成身分識別方面，要了解當事人關係是否為家庭暴力防治法之家庭成員或年滿 14 歲 以上遭未同居親密關係加害人施暴保護範圍", "在查明保護令狀態方面，包括有無保護令、保護令之效期及款項，如有違反家暴防治法之 情事，應即時啟動相關保護措施", "關於啟動安全措施方面，包括聲請保護令、護送安置或就醫、查訪告誡相對人、及視個案 轉介網絡單位進行戒癮治療等其他必要危害防止措施", "在責任通報方面，執行職務知有疑似家暴，應立即通報當地主管機關，至遲不得逾 24 小 時，如有違反，得處新臺幣6千元以上3萬元以下之罰鍰"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:11+00:00", "source_pdf_sha1": "73d23c08e8de", "answer_pdf_sha1": "2ec31371094c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00068', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '警員甲於西門町徒步區執行盤查勤務，攔查到通緝中之A。在盤查過程中，A突然跳上自小 客車，並急速駕車試圖衝撞周遭人潮，當時現場人流密集，部分群眾已因閃避不及跌倒受傷。 警員甲判斷若不即時制止，恐將釀成重大死傷，遂拔槍意圖擊破車輛前輪輪胎以阻止車輛暴 衝。在開出第一槍時，子彈穿透擋風玻璃，擊中A之腹部，造成其大量出血，送醫後宣告不 治死亡。事後調查發現：當時甲距離A車輛約8公尺，且A已加速衝撞方向為人潮密集區； 現場還有其他巡邏員警與群眾，並無明顯掩護物可迅速阻擋車輛行進；員警甲共射擊2發， 僅第一發誤中A，第二發未命中。下列關於警員甲之射擊行為的描述，何者正確？', '["甲使用槍械未先行口頭告知，已違反比例原則，因此射擊違法", "甲以槍械射擊車輛導致A死亡，因結果重大超過預期，因此構成違法使用槍械", "甲應等待車輛衝撞人群傷亡之後，再行開槍制止，提前射擊違反必要性原則", "甲在無掩蔽物、短距離且A已加速衝撞人群之情形下，基於制止重大危害而射擊，符合警 械使用合法條件"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:11+00:00", "source_pdf_sha1": "73d23c08e8de", "answer_pdf_sha1": "2ec31371094c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00069', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '刑事案件由犯罪地之警察機關管轄，下列敘述何者正確？', '["犯罪行為之發生或結果橫跨二個以上警察機關管轄區域者，由共同上級之警察機關決定由 那個警察機關主辦，其他警察機關則將有關資料送請併案偵辦", "凡是犯罪地屬專業警察機關管轄區域者，均以該警察機關主辦為原則，其他相關警察機關 配合之", "捷運或輕軌移動車廂內發生之案件，由發生地之警察機關管轄，無法確認發生地時，則由 被害人下車停靠站所在地警察機關管轄", "涉及帳戶匯款案件，由帳戶開立之銀行所在地之警察機關管轄，其他相關警察機關協同辦 理。但同時涉及當面取款詐欺案件者，統一由取款地之警察機關為主辦單位"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:11+00:00", "source_pdf_sha1": "73d23c08e8de", "answer_pdf_sha1": "2ec31371094c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00070', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '關於專案小組案件現場處理，下列敘述何者正確？', '["遇疑似爆裂物時，勘察人員應自行處理排除危險，以把握時機", "若遇有裝備器材不足或技術困難時，勘查人員應通報警政署刑事警察局地區防爆隊至現場 排除危害", "已爆炸之現場，經初步觀察安全無虞後，勘察人員即可自行採集殘留物", "警政署刑事警察局地區防爆隊專責協助現場爆裂物之排除，而勘察人員則負責殘骸採樣"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:11+00:00", "source_pdf_sha1": "73d23c08e8de", "answer_pdf_sha1": "2ec31371094c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00071', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '關於跟蹤與監視之區別，下列敘述何者正確？', '["跟蹤主要強調流動性與持續性，監視則強調隱密性與長時間定點蒐證，二者均屬於秘密觀 察活動", "跟蹤以保持目標於可視範圍內為主，其形態通常為流動觀察；監視則以隱匿於定點、持續 觀察特定人、物、處所為主", "跟蹤著重於固定地點之長時間觀察，必要時配合移動偵查；監視則為針對特定對象之動態 行動，進行長期觀察", "跟蹤屬於定點觀察，將視目標行動變動再進行追蹤；監視屬於流動觀察，以即時掌握目標 行蹤為目的"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:11+00:00", "source_pdf_sha1": "73d23c08e8de", "answer_pdf_sha1": "2ec31371094c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00072', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '關於專案小組之設立，下列敘述何者正確？', '["當任何刑事案件發生後不能即時獲得線索予以偵破，而必須有關單位協助偵查時，得成立 專案小組負責偵查", "專案小組僅能由內政部警政署設立，以該署刑事警察局長為召集人，並邀同相關警察局局 長及刑警大隊大隊長參加", "由內政部警政署設立之專案小組，可由主持人或召集人視案件實際需要決定參加人數，成 員可隨偵查進展靈活調整，無須固定不變", "鐵路警察局若有設立專案小組之情形，須報請警政署刑事警察局同意後，依該署設置標準 獨立成立專案小組"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:11+00:00", "source_pdf_sha1": "73d23c08e8de", "answer_pdf_sha1": "2ec31371094c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00073', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '警察人員在執行酒測勤務時，如果未完整告知受測人拒絕酒測之「全部」法律效果，如警 員P未事先告知受測人A拒絕酒測將會被施以交通安全講習，是否仍得裁罰該拒絕酒測之 受測人？', '["不可以，因為警員P所實施之處分為裁罰性質，必須事先告知；未告知者不得處罰", "可以，因為警員P所實施之處分並非行政罰，參加講習並非咎責，所以未告知也不影響法 律效果", "可以，因為警員P雖未告知，但道路交通管理處罰條例已有明文，用路人本有知法之義務， 不得主張不知法律而不罰", "要視情況加以區分，只要是屬於裁罰性的處分，如罰鍰、吊銷駕照、施以講習等必須事先 告知；但不具有裁罰性質者，不用告知，仍然生效"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:11+00:00", "source_pdf_sha1": "73d23c08e8de", "answer_pdf_sha1": "2ec31371094c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00074', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '有關詐欺案件防治措施的敘述，下列何者正確？', '["警察機關得於偵辦詐欺案件時，逕行要求金融機構立即凍結所有可疑帳戶，無須依法通知 或記錄，避免打草驚蛇", "網路廣告平台業者知悉其平台上有明顯涉及詐欺之廣告時，應主動或依通知期限內移除該 廣告，並提供委託刊播者及出資者之資料予以司法警察機關", "電信業者得基於防詐考量，逕行限制或終止用戶所有通訊服務，而無需核對或更新用戶資 料，確保迅速斷絕詐欺聯繫", "法人之代表人、法人或自然人之代理人、受僱人或其他從業人員，因執行業務犯詐欺犯罪 者，因法人非自然人，僅處罰行為人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:11+00:00", "source_pdf_sha1": "73d23c08e8de", "answer_pdf_sha1": "2ec31371094c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00075', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '關於情報諮詢之進行，下列敘述何者正確？', '["情報諮詢之對象應審慎遴選，注重對象之合作意願，以及與偵查人員之信賴關係，若有特 殊地位者（如在幫派中），應優先考慮，以利辦案", "重點情報諮詢地點應設於易為不法分子藏匿、活動或銷贓之場所，如夜市、港口、旅館、 當舖、網咖等", "警察與情報諮詢對象接觸時，必須保密，不得對外透露諮詢對象身分；任務交付須保密且 謹慎，並以蒐集情報為重點；必要時，得使諮詢對象直接參與辦案行動", "情報資料應依登記、分析、研判及運用程序處理；有價值者持續偵查，無法運用之情報也 應保存十年，以供後續釐清責任"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:11+00:00", "source_pdf_sha1": "73d23c08e8de", "answer_pdf_sha1": "2ec31371094c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL),
  ('police-8b7f1efc-moex-00076', 'police-8b7f1efc', 'police-8b7f1efc-moex-114-4300c406', 'sub-police-8b7f1efc-02', NULL, 'single_choice', '有關偵查不公開原則之規定事項，下列敘述何者正確？', '["司法警察官禁止辯護人在場，致犯罪嫌疑人無其他辯護人在場陪同，應再行告知第 95 條 第1項之各款事項", "應遵循偵查不公開原則之人員，包括辯護人、告訴代理人及被告", "犯罪嫌疑人對於司法警察官禁止其辯護人在場不服者，得向該管法院聲請撤銷或變更之", "偵查不公開作業辦法，由法務部會同內政部定之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:11+00:00", "source_pdf_sha1": "73d23c08e8de", "answer_pdf_sha1": "2ec31371094c", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "501", "s": "1207", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "偵查法學與犯罪偵查", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "行政警察人員"}'::jsonb, NULL)
